/**
 * Compute installment_amount (in centavos) for a given principal and installments.
 * Uses compound interest (Price method — tabela Price — standard in Brazil).
 *
 * Formula: PMT = PV × [r(1+r)^n] / [(1+r)^n - 1]
 *   where PV = principal (centavos), r = monthly rate, n = installments
 *
 * For n=1: returns the full amount (no interest on single installment).
 */
function computeInstallmentAmount(totalCents, installments, monthlyRate = exports.DEFAULT_MONTHLY_JUROS_RATE) {
    if (installments <= 1)
        return totalCents;
    const r = monthlyRate;
    const n = installments;
    // Price formula
    const factor = (r * (1 + r) ** n) / ((1 + r) ** n - 1);
    return Math.round(totalCents * factor);
}
